                      </defs>
                      <rect width="100%" height="100%" fill="url(#bookPattern)" />
                    </svg>
                  </div>

                  {/* Cover Content */}
                  <div className="relative z-10 h-full flex flex-col items-center justify-center p-8 text-primary-foreground">
