                    whileHover={{ scale: 1.05 }}
                    whileTap={{ scale: 0.95 }}
                  >
                    {i + 1}. {chapter}
                  </motion.span>
                ))}
              </div>
            </div>

            {/* Testimonial */}
            <div className="border-l-2 border-primary pl-4 mb-8">
              <Quote className="h-4 w-4 text-muted-foreground mb-2" />
              <motion.p 
